    return np.where(normalized >= threshold, 'High Volume Cluster', 'Normal')

def detect_divergence(price, delta, lookback=20):
    price_peaks = find_peaks(price, lookback)
    delta_peaks = find_peaks(delta, lookback)

    regular_bearish = (price_peaks > price_peaks[-1]) and (delta_peaks < delta_peaks[-1])
    regular_bullish = (price_peaks < price_peaks[-1]) and (delta_peaks > delta_peaks[-1])

    hidden_bullish = (price_peaks > price_peaks[-1]) and (delta_peaks > delta_peaks[-1])

    return {'regular_bearish': regular_bearish, 
            'regular_bullish': regular_bullish,
            'hidden_bullish': hidden_bullish}

def detect_imbalance_patterns(bid_volume, ask_volume, threshold=0.7):
    ratio = ask_volume / bid_volume

    if ratio > (1 + threshold):
        return 'Strong Buys' if ask_volume > bid_volume else 'Strong Sells'
    elif ratio < (1 - threshold):
        return 'Strong Sells' if ask_volume < bid_volume else 'Strong Buys'
    else:
        return 'Balanced'

def calculate_cumulative_imbalance(imbalances):
    return np.cumsum(imbalances)

def detect_delta_divergence(price, cumulative_delta, lookback=30):
    price_peaks = find_peaks(price, lookback)
    delta_peaks = find_peaks(cumulative_delta, lookback)

    bearish_divergence = (price_peaks > price_peaks[-1]) and (delta_peaks < delta_peaks[-1])
    bullish_divergence = (price_peaks < price_peaks[-1]) and (delta_peaks > delta_peaks[-1])

    return {'bearish': bearish_divergence, 'bullish': bullish_divergence}

def detect_stacked_imbalance(ask_vol, bid_vol, min_stack=3):
    imbalances = ask_vol - bid_vol
    direction = np.sign(imbalances)

    stacks = []
    current = []
    for i, d in enumerate(direction):
        if d == 0:
            continue
        if len(current) > 0 and d != direction[current[-1]]:
            if len(current) >= min_stack:
                stacks.append(current)
            current = []
        current.append(i)

    return stacks

def calculate_initial_balance(price_data, lookback_minutes=60):
    first_hour = price_data[price_data['time'] <= '10:30:00']
    ib_high = max(first_hour['high'])
    ib_low = min(first_hour['low'])
    ib_range = ib_high - ib_low

    # Calculate IB breakout levels
    ib_breakout_high = ib_high + (ib_range * 0.25)
    ib_breakout_low = ib_low - (ib_range * 0.25)

    return {'high': ib_high, 'low': ib_low, 'range': ib_range, 
            'breakout_high': ib_breakout_high, 'breakout_low': ib_breakout_low}

def detect_single_prints(price_levels, tpo_counts, threshold=1):
    single_prints = [i for i, count in enumerate(tpo_counts) if count <= threshold]

    # Find consecutive single prints (gaps)
    gaps = []
    current_gap = []
    for idx in single_prints:
        if len(current_gap) == 0:
            current_gap.append(idx)
        elif idx == current_gap[-1] + 1:
            current_gap.append(idx)
        else:
            if len(current_gap) >= 2:
                gaps.append(current_gap)
            current_gap = [idx]

    return {'single_prints': single_prints, 'gaps': gaps}

def detect_double_distribution(price_levels, volumes, min_distribution_size=5):
    # Find potential distribution centers (POCs)
    pocs = []
    for i in range(len(volumes)):
        if volumes[i] > volumes[i-1] and volumes[i] > volumes[i+1]:
            pocs.append(i)

    # Group into distributions
    distributions = []
    current_dist = [pocs[0]]
    for i in range(1, len(pocs)):
        if pocs[i] - pocs[i-1] > min_distribution_size:
            distributions.append(current_dist)
            current_dist = [pocs[i]]
        else:
            current_dist.append(pocs[i])
    distributions.append(current_dist)

    return distributions

