def detect_icebergs(order_data, time_window=60):
    # Group orders by price level
    levels = {} 
    for order in order_data:
        if order.price not in levels:
            levels[order.price] = []
        levels[order.price].append(order)

    # Analyze for iceberg patterns
    icebergs = []
    for price, orders in levels.items():
        sizes = [o.size for o in orders]
        times = [o.time for o in orders]

        # Check for consistent small sizes
        if len(sizes) > 5 and np.std(sizes) < np.mean(sizes) * 0.3:
            # Check for time pattern
            time_diffs = np.diff(times)
            if np.mean(time_diffs) < time_window:
                icebergs.append({
                    'price': price,
                    'avg_size': np.mean(sizes),
                    'count': len(sizes),
                    'total': sum(sizes)
                })

    return icebergs

def detect_spoofing(order_book, time_window=60):
    spoofing_candidates = []

    for price_level in order_book.levels:
        orders = order_book.get_orders(price_level)

        # Track order lifecycle
        active_orders = []
        for order in orders:
            if order.status == 'active':
                active_orders.append(order)
            elif order.status == 'canceled':
                # Check if order was active briefly
                lifetime = order.cancel_time - order.place_time
                if lifetime < time_window and order.size > 100:
                    spoofing_candidates.append(order)

        # Calculate cancellation rate
        cancel_rate = len(spoofing_candidates) / len(orders)

        if cancel_rate > 0.4:
            return {'level': price_level, 'spoofing': True, 'rate': cancel_rate}

    return {'spoofing': False}

