def execute_twap(total_quantity, duration, slices):
    slice_quantity = total_quantity // slices
    slice_interval = duration // slices
    remaining = total_quantity
    for i in range(slices):
        current_slice = min(slice_quantity, remaining)
        market_order(symbol, current_slice)
        remaining -= current_slice
        time.sleep(slice_interval)
