    remaining = total_quantity
    for interval in volume_profile.intervals:
        interval_volume = volume_profile.get_volume(interval)
        interval_pct = interval_volume / total_volume
        slice_size = total_quantity * interval_pct
        market_order(symbol, slice_size)
        remaining -= slice_size
