    def __init__(self, limits):
        self.position_limit = limits['position']
        self.order_size_limit = limits['order_size']
        self.daily_loss_limit = limits['daily_loss']
        self.daily_pnl = 0
        self.positions = {}

    def pre_trade_check(self, order):
        if order.size > self.order_size_limit:
            raise OrderSizeLimitExceeded()
        if self.get_total_position() + order.size > self.position_limit:
            raise PositionLimitExceeded()
        if self.daily_pnl < -self.daily_loss_limit:
