class CircuitBreakerSystem:
    def __init__(self, levels, durations):
        self.levels = levels  # [7%, 13%, 20%]
        self.durations = durations  # [5, 15, 30] minutes
        self.status = 'OPEN'
        self.triggered_level = None

    def monitor_market(self, price, previous_close):
        decline = (previous_close - price) / previous_close * 100
        for i, level in enumerate(self.levels):
            if decline >= level and self.triggered_level is None:
                self.trigger(level, self.durations[i])
                break

    def trigger(self, level, duration):
        self.status = 'HALTED'
        self.triggered_level = level
        self.halt_end_time = time.now() + duration
        return {'status': 'HALTED', 'level': level, 'duration': duration}

class PositionLimitSystem:
    def __init__(self, limits):
        self.absolute_limit = limits['absolute']
        self.percentage_limit = limits['percentage']
        self.sector_limit = limits['sector']
        self.positions = {}
        self.portfolio_value = 0

    def check_position(self, security, proposed_size):
        current = self.positions.get(security, 0)
        new_total = current + proposed_size

        if new_total > self.absolute_limit:
            raise AbsoluteLimitExceeded()

        if (new_total / self.portfolio_value * 100) > self.percentage_limit:
            raise PercentageLimitExceeded()

        sector_exposure = self.calculate_sector_exposure(security)
        if sector_exposure > self.sector_limit:
            raise SectorLimitExceeded()

        return True

class OrderVelocityCheck:
    def __init__(self, limits):
        self.orders_per_second = limits['per_second']
        self.orders_per_minute = limits['per_minute']
        self.order_to_trade_ratio = limits['ratio']
        self.order_history = []
        self.trade_history = []

    def check(self, order):
        self.order_history.append(time.now())
        self.clean_old_records()

        if self.count_last_second() > self.orders_per_second:
            raise VelocityLimitExceeded('orders_per_second')

        if self.count_last_minute() > self.orders_per_minute:
            raise VelocityLimitExceeded('orders_per_minute')

        ratio = self.get_order_to_trade_ratio()
        if ratio > self.order_to_trade_ratio:
            raise VelocityLimitExceeded('order_to_trade_ratio')

        return True

