                if rsi_at_high_j < rsi_at_high_i:
                    divergences.append({
                        'start': price_highs[i],
                        'end': price_highs[j],
                        'type': 'bearish',
                        'strength': (rsi_at_high_i - rsi_at_high_j) / rsi_at_high_i * 100
                    })

    return pd.DataFrame(divergences)

bearish_div = detect_bearish_divergence(price_swings, rsi_swings, data['close'], data['RSI'])
