def weighted_mtf_signal(daily_rsi, fourh_rsi, oneh_rsi, 
                        weights={'daily': 0.5, '4h': 0.3, '1h': 0.2},
                        ob=70, os=30):
    """Generate weighted signal from multiple timeframes"""

    def normalize_rsi(rsi):
        """Convert RSI to -1 to 1 scale"""
        if rsi > ob:
            return -min(1, (rsi - ob) / (100 - ob))
        elif rsi < os:
            return min(1, (os - rsi) / os)
        else:
            return 0

    daily_score = normalize_rsi(daily_rsi) * weights['daily']
    fourh_score = normalize_rsi(fourh_rsi) * weights['4h']
    oneh_score = normalize_rsi(oneh_rsi) * weights['1h']

    total_score = daily_score + fourh_score + oneh_score

    if total_score > 0.3:
        return 'BUY', total_score
    elif total_score < -0.3:
        return 'SELL', total_score
    else:
        return 'NEUTRAL', total_score

